// MARK: - Certificate Pin Store

struct CertificatePinStore {
    // SHA-256 hashes of the Subject Public Key Info (SPKI) for api.example.com
    // In production, include both the leaf and at least one backup pin
    static let apiExamplePins: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=", // Primary leaf pin
        "CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="  // Backup pin
    ]
    
    static func pins(for host: String) -> Set<String>? {
        switch host {
        case "api.example.com":
            return apiExamplePins
        default:
            return nil
        }
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    static let shared = SSLPinningDelegate()
    
    private override init() {
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    func urlSession(
        _ session: URLSession,
        task: URLSessionTask,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    private func handleChallenge(
        _ challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust,
              let host = Optional(challenge.protectionSpace.host) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // For legacy.internal over HTTP, no server trust challenge is expected.
        // If somehow one arrives, reject it.
        if host == "legacy.internal" {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Perform standard certificate validation first
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            print("[SSL] Certificate validation failed for \(host): \(error?.localizedDescription ?? "unknown")")
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // If we have pins for this host, enforce certificate pinning
        if let expectedPins = CertificatePinStore.pins(for: host) {
            guard validatePins(serverTrust: serverTrust, expectedPins: expectedPins, host: host) else {
                print("[SSL] Certificate pinning failed for \(host)")
                completionHandler(.cancelAuthenticationChallenge, nil)
                return
            }
        }
        
        // Validation passed
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    private func validatePins(serverTrust: SecTrust, expectedPins: Set<String>, host: String) -> Bool {
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        
        for index in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, index) else {
                continue
            }
            
            let publicKeyHash = sha256HashOfSPKI(for: certificate)
            if let hash = publicKeyHash, expectedPins.contains(hash) {
                print("[SSL] Pin matched for \(host) at chain index \(index)")
                return true
            }
        }
        
        print("[SSL] No pin matched for \(host) across \(certificateCount) certificates in chain")
        return false
    }
    
    private func sha256HashOfSPKI(for certificate: SecCertificate) -> String? {
        guard let publicKey = SecCertificateCopyKey(certificate) else {
            return nil
        }
        
        var error: Unmanaged<CFError>?
        guard let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            return nil
        }
        
        // Hash the public key data with SHA-256
        let hash = SHA256.hash(data: publicKeyData)
        return Data(hash).base64EncodedString()
    }
}

// MARK: - API Environment Configuration

enum APIEnvironment {
    case production
    case legacyInternal
    
    var baseURL: URL {
        switch self {
        case .production:
            return URL(string: "https://api.example.com")!
        case .legacyInternal:
            return URL(string: "http://legacy.internal")!
        }
    }
    
    var requiresSSLPinning: Bool {
        switch self {
        case .production:
            return true
        case .legacyInternal:
            return false // HTTP only, no TLS
        }
    }
    
    var isSecure: Bool {
        switch self {
        case .production:
            return true
        case .legacyInternal:
            return false
        }
    }
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case insecureConnectionNotAllowed(String)
    case sslPinningFailed
    case noData
    case httpError(statusCode: Int, data: Data?)
    case decodingError(Error)
    case networkError(Error)
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .insecureConnectionNotAllowed(let host):
            return "Insecure connection to \(host) is not allowed outside of legacy.internal"
        case .sslPinningFailed:
            return "SSL certificate pinning validation failed"
        case .noData:
            return "No data received"
        case .httpError(let statusCode, _):
            return "HTTP error: \(statusCode)"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        }
    }
}

// MARK: - Network Client

final class NetworkClient {
    
    static let shared = NetworkClient()
    
    // Session with SSL pinning for secure connections
    private let secureSession: URLSession
    
    // Session for legacy internal connections (HTTP allowed only for legacy.internal via ATS exception)
    private let legacySession: URLSession
    
    private let allowedInsecureHosts: Set<String> = ["legacy.internal"]
    
    private init() {
        let secureConfig = URLSessionConfiguration.default
        secureConfig.tlsMinimumSupportedProtocolVersion = .TLSv12
        secureConfig.timeoutIntervalForRequest = 30
        secureConfig.timeoutIntervalForResource = 60
        
        self.secureSession = URLSession(
            configuration: secureConfig,
            delegate: SSLPinningDelegate.shared,
            delegateQueue: nil
        )
        
        let legacyConfig = URLSessionConfiguration.default
        legacyConfig.timeoutIntervalForRequest = 30
        legacyConfig.timeoutIntervalForResource = 60
        
        // Legacy session uses default delegate (no pinning needed for HTTP)
        self.legacySession = URLSession(configuration: legacyConfig)
    }
    
    // MARK: - Public API
    
    func request<T: Decodable>(
        environment: APIEnvironment,
        path: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil,
        responseType: T.Type
    ) async throws -> T {
        let url = environment.baseURL.appendingPathComponent(path)
        
        // Security check: reject insecure connections to non-whitelisted hosts
        if !environment.isSecure {
            guard let host = url.host, allowedInsecureHosts.contains(host) else {
                throw NetworkError.insecureConnectionNotAllowed(url.host ?? "unknown")
            }
            print("[Network] ⚠️ Using insecure HTTP connection to legacy host: \(url.host ?? "unknown")")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.httpBody = body
        
        // Set default headers
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Apply custom headers
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        // Choose the appropriate session
        let session = environment.isSecure ? secureSession : legacySession
        
        let (data, response): (Data, URLResponse)
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkError(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw NetworkError.httpError(statusCode: httpResponse.statusCode, data: data)
        }
        
        do {
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            decoder.keyDecodingStrategy = .convertFromSnakeCase
            return try decoder.decode(T.self, from: data)
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
}

