// MARK: - API Service Layer

final class APIService {
    
    private let client = NetworkClient.shared
    
    // MARK: - Production API (HTTPS with certificate pinning)
    
    func fetchUsers() async throws -> [User] {
        return try await client.request(
            environment: .production,
            path: "/v1/users",
            responseType: APIResponse<[User]>.self
        ).data ?? []
    }
    
    func createUser(name: String, email: String) async throws -> User {
        let body = try JSONEncoder().encode(["name": name, "email": email])
        
        let response = try await client.request(
            environment: .production,
            path: "/v1/users",
            method: .post,
            body: body,
            responseType: APIResponse<User>.self
        )
        
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    // MARK: - Legacy Internal System (HTTP - narrowly scoped ATS exception)
    
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        return try await client.request(
            environment: .legacyInternal,
            path: "/records",
            responseType: [LegacyRecord].self
        )
    }
    
    func fetchLegacyRecord(id: String) async throws -> LegacyRecord {
        return try await client.request(
            environment: .legacyInternal,
            path: "/records/\(id)",
            responseType: LegacyRecord.self
        )
    }
}

