import SwiftUI

struct ContentView: View {
    @State private var users: [User] = []
    @State private var legacyRecords: [LegacyRecord] = []
    @State private var errorMessage: String?
    @State private var isLoading = false
    
    private let apiService = APIService()
    
    var body: some View {
        NavigationView {
            List {
                Section(header: sectionHeader(title: "Production API", subtitle: "HTTPS + Certificate Pinning", secure: true)) {
                    if users.isEmpty && !isLoading {
                        Text("No users loaded")
                            .foregroundColor(.secondary)
                    }
                    ForEach(users, id: \.id) { user in
                        VStack(alignment: .leading) {
                            Text(user.name)
                                .font(.headline)
                            Text(user.email)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                Section(header: sectionHeader(title: "Legacy Internal", subtitle: "HTTP (ATS Exception)", secure: false)) {
                    if legacyRecords.isEmpty && !isLoading {
                        Text("No records loaded")
                            .foregroundColor(.secondary)
                    }
                    ForEach(legacyRecords, id: \.recordId) { record in
                        VStack(alignment: .leading) {
                            Text("Record: \(record.recordId)")
                                .font(.headline)
                            Text(record.data)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                if let error = errorMessage {
                    Section(header: Text("Error")) {
                        Text(error)
                            .foregroundColor(.red)
                            .font(.caption)
                    }
                }
            }
            .navigationTitle("Network Client")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button(action: loadData) {
                        if isLoading {
                            ProgressView()
                        } else {
                            Image(systemName: "arrow.clockwise")
                        }
                    }
                    .disabled(isLoading)
                }
            }
            .onAppear {
                loadData()
            }
        }
    }
    
    private func sectionHeader(title: String, subtitle: String, secure: Bool) -> some View {
        HStack {
            Image(systemName: secure ? "lock.shield.fill" : "exclamationmark.triangle.fill")
                .foregroundColor(secure ? .green : .orange)
            VStack(alignment: .leading) {
                Text(title)
                Text(subtitle)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
        }
    }
    
    private func loadData() {
        isLoading = true
        errorMessage = nil
        
        Task {
            do {
                async let usersResult = apiService.fetchUsers()
                async let recordsResult = apiService.fetchLegacyRecords()
                
                let (fetchedUsers, fetchedRecords) = try await (usersResult, recordsResult)
                
                await MainActor.run {
                    self.users = fetchedUsers
                    self.legacyRecords = fetchedRecords
                    self.isLoading = false
                }
            } catch {
                await MainActor.run {
                    self.errorMessage = error.localizedDescription
                    self.isLoading = false
                }
            }
        }
    }
}

